const allData = $("Credilus Request").first().json.data;
const record = allData[0];

const emails = record.EMAILS;
const nomeCompleto = record.NOME || "";
const cpf = record.CPFCNPJ || "";

function parseEmailList(emailString) {
  if (emailString) {
    return emailString
      .split(',')
      .map(email => email.trim())
      .filter(email => email !== '');
  }
  return [];
}

let emailList = parseEmailList(emails);

if (emailList.length === 0) {
  const nomes = nomeCompleto.trim().split(" ");
  const primeiroNome = nomes[0]?.toLowerCase() || "usuario";
  const ultimoNome = nomes[nomes.length - 1]?.toLowerCase() || "padrao";
  const cpfDigitos = cpf.replace(/\D/g, ""); // remove caracteres não numéricos
  const ultimosDigitos = cpfDigitos.slice(-2) || "00";
  const emailGerado = `${primeiroNome}${ultimoNome}${ultimosDigitos}@gmail.com`;
  emailList = [emailGerado];
}

return {
  emails: emailList
};

const phoneData = $("Merge").first().json.remoteJid;

function extractPhoneInfo(whatsappString) {
    const match = whatsappString?.match(/^55(\d{2})(\d{8,9})@s\.whatsapp\.net$/);

    if (match) {
        return {
            ddd: match[1],
            phone: match[2]
        };
    }

    return null; // Retorna null se o formato não corresponder
}

const result = extractPhoneInfo(phoneData);

// O n8n espera um array de objetos como saída no nó de código
return result ? [result] : [];

const raw = items[0].json.query;

// Substitui aspas simples por aspas duplas e converte para objeto
const cleaned = raw.replace(/'/g, '"');
const parsed = JSON.parse(cleaned);

return [{ json: parsed }];

// Pega o array do campo body
let data = items[0].json.body;

// Corrige problemas de digitação, como "96}"
data = data.map(item => {
  return {
    ...item,
    numeroParcelas: item.numeroParcelas?.toString().replace(/[^\d]/g, '') || null,
    limiteDisponivel: parseFloat(item.limiteDisponivel) || null,
    valorParcela: parseFloat(item.valorParcela) || null
  };
});

// Retorna o primeiro item do array
return [{ json: data[0] }];

function decodeHtmlEntities(str) {
  return str
    .replace(/&#xE1;/g, 'á')
    .replace(/&#xE0;/g, 'à')
    .replace(/&#xE2;/g, 'â')
    .replace(/&#xEA;/g, 'ê')
    .replace(/&#xE3;/g, 'ã')
    .replace(/&#xED;/g, 'í')
    .replace(/&#xF3;/g, 'ó')
    .replace(/&#xFA;/g, 'ú')
    .replace(/&#xF4;/g, 'ô')
    .replace(/&#xE9;/g, 'é')
    .replace(/&quot;/g, '"');
}

const rawMessage = items[0].json.error.message;

const match = rawMessage.match(/<faultstring>(.*?)<\/faultstring>/);

if (match && match[1]) {
  const decoded = decodeHtmlEntities(match[1]);

  const cleanedMessage = decoded.replace(/^.*Lista de inconsistências:/i, '').trim();

  return [{ json: { mensagemLegivel: cleanedMessage } }];
} else {
  return [{ json: { mensagemLegivel: 'Mensagem de erro não encontrada.' } }];
}

